//refAssemblies: TCAdmin.SDK.dll, TCAdmin.Docker.SDK.dll, TCAdmin.Web.Shared.dll, TCAdmin.Scripting.dll, TCAdmin.Monitor.dll, Docker.DotNet.dll, System.Security.Cryptography.dll, System.Net.Primitives.dll
using System;
using System.IO;
using System.Linq;
using System.Text;
using System.Collections.Generic;
using System.Security.Cryptography;
using System.Security.Cryptography.X509Certificates;
using Docker.DotNet.Models;

var Globals = new TCAdmin.Scripting.Engines.Addons.CSharpDockerGlobals(); // DO NOT MODIFY THIS LINE
var service = Globals.ThisService;
var startParams = Globals.ThisContainerStartParameters;
var root = service.RootDirectory;

// ---- local helpers (declared first; safe to call below) -------------------
string GetVar(string key, string fallback)
{
    try
    {
        if (service.Variables != null && service.Variables.ContainsKey(key))
        {
            var v = service.Variables[key];
            if (v != null)
            {
                var s = v.ToString();
                if (!string.IsNullOrWhiteSpace(s)) return s;
            }
        }
    }
    catch { }
    return fallback;
}

string NormalizeInt(string val, string fallback)
{
    if (string.IsNullOrWhiteSpace(val)) return fallback;
    if (int.TryParse(val, out var i)) return i.ToString();
    if (double.TryParse(val, System.Globalization.NumberStyles.Any, System.Globalization.CultureInfo.InvariantCulture, out var d))
        return ((int)d).ToString();
    return fallback;
}

bool IsTrue(string val)
{
    val = (val ?? "").Trim().ToLowerInvariant();
    return val == "true" || val == "1" || val == "yes";
}

void SetEnv(IList<string> env, string key, string val)
{
    for (int i = env.Count - 1; i >= 0; i--)
        if (env[i].StartsWith(key + "=", StringComparison.Ordinal)) env.RemoveAt(i);
    env.Add(key + "=" + val);
}

// ---------------------------------------------------------------------------
// 1. Read the per-service settings the owner chose in the Create-Service
//    wizard's "config.json" config-file editor. Those editor values are
//    persisted on Service.Variables keyed by the editor control Id
//    (connectionMode / host / port / ...), and the config.json template is
//    also rendered to disk. Reading Service.Variables here means a later
//    edit of config.json in the file manager (reverse-synced to
//    Service.Variables) is picked up on the next Restart. Defaults keep a
//    container bootable if any value is missing.
// ---------------------------------------------------------------------------
string connectionMode   = GetVar("connectionMode", "localhost").Trim().ToLowerInvariant();
string dbHost           = GetVar("host", "").Trim();
string dbPort           = NormalizeInt(GetVar("port", "3306"), "3306");
string uploadLimit      = GetVar("uploadLimit", "256M").Trim();
string memoryLimit      = GetVar("memoryLimit", "512M").Trim();
string maxExecutionTime = NormalizeInt(GetVar("maxExecutionTime", "600"), "600");
bool   allowNoPassword  = IsTrue(GetVar("allowNoPassword", "False"));

startParams.Env ??= new List<string>();
startParams.HostConfig ??= new HostConfig();
startParams.HostConfig.ExtraHosts ??= new List<string>();

// ---------------------------------------------------------------------------
// 2. The official phpmyadmin:apache entrypoint runs as root and bootstraps
//    /etc/phpmyadmin (writes config.secret.inc.php, touches config.user.inc.php)
//    inside a directory owned by www-data. TCAdmin's default container hardening
//    drops dac_override/fowner/fsetid, which stops root from writing files it
//    doesn't own -> the entrypoint fails with "Permission denied". Restore just
//    those three caps so the image can bootstrap; net_raw / sys_ptrace / mknod /
//    etc. stay dropped.
// ---------------------------------------------------------------------------
if (startParams.HostConfig.CapDrop != null)
{
    var restore = new HashSet<string>(StringComparer.OrdinalIgnoreCase) { "dac_override", "fowner", "fsetid" };
    startParams.HostConfig.CapDrop = startParams.HostConfig.CapDrop.Where(c => !restore.Contains(c)).ToList();
}

// ---------------------------------------------------------------------------
// 3. Translate the settings into phpMyAdmin environment variables. The
//    official image reads these on startup to generate config.inc.php.
// ---------------------------------------------------------------------------
if (!string.IsNullOrEmpty(uploadLimit))      SetEnv(startParams.Env, "UPLOAD_LIMIT", uploadLimit);
if (!string.IsNullOrEmpty(memoryLimit))      SetEnv(startParams.Env, "MEMORY_LIMIT", memoryLimit);
if (!string.IsNullOrEmpty(maxExecutionTime)) SetEnv(startParams.Env, "MAX_EXECUTION_TIME", maxExecutionTime);

if (connectionMode == "arbitrary")
{
    // Login page shows a "Server" field so the user can connect to any host.
    SetEnv(startParams.Env, "PMA_ARBITRARY", "1");
}
else
{
    // "Localhost" = the Docker host's MySQL. Reach it via the bridge gateway
    // (works even when the bridge has no outbound NAT). An explicit host wins.
    var hostTarget = string.IsNullOrEmpty(dbHost) ? "host.docker.internal" : dbHost;
    SetEnv(startParams.Env, "PMA_HOST", hostTarget);
    if (!string.IsNullOrEmpty(dbPort)) SetEnv(startParams.Env, "PMA_PORT", dbPort);
    if (hostTarget == "host.docker.internal" &&
        !startParams.HostConfig.ExtraHosts.Contains("host.docker.internal:host-gateway"))
    {
        startParams.HostConfig.ExtraHosts.Add("host.docker.internal:host-gateway");
    }
}

// "Allow blank-password logins" has no env var. The image supports delivering an
// extra config via PMA_USER_CONFIG_BASE64 (base64 -> /etc/phpmyadmin/config.user.inc.php),
// written by the image itself — cleaner than bind-mounting a read-only file, which
// would collide with the entrypoint's `touch config.user.inc.php`.
if (allowNoPassword)
{
    var php =
        "<?php\n" +
        "if (isset($cfg['Servers']) && is_array($cfg['Servers'])) {\n" +
        "    foreach ($cfg['Servers'] as $k => $v) {\n" +
        "        $cfg['Servers'][$k]['AllowNoPassword'] = true;\n" +
        "    }\n" +
        "}\n";
    SetEnv(startParams.Env, "PMA_USER_CONFIG_BASE64", Convert.ToBase64String(Encoding.UTF8.GetBytes(php)));
}

// ---------------------------------------------------------------------------
// 4. Self-signed certificate + Apache TLS wiring, bind-mounted into the
//    container (same idea as the nginx blueprint, adapted to php:apache's
//    /etc/apache2 layout). Pure .NET crypto — no openssl, no container net.
// ---------------------------------------------------------------------------
var tlsDir = Path.Combine(root, "tls");
Directory.CreateDirectory(tlsDir);

var crtPath = Path.Combine(tlsDir, "server.crt");
var keyPath = Path.Combine(tlsDir, "server.key");

var host = service.IPAddress;
if (string.IsNullOrWhiteSpace(host)) { host = "localhost"; }

Func<string, byte[], string> toPem = (label, der) =>
{
    var b64 = Convert.ToBase64String(der);
    var sb = new StringBuilder();
    sb.Append("-----BEGIN ").Append(label).Append("-----\n");
    for (int i = 0; i < b64.Length; i += 64)
        sb.Append(b64.Substring(i, Math.Min(64, b64.Length - i))).Append('\n');
    sb.Append("-----END ").Append(label).Append("-----\n");
    return sb.ToString();
};

if (!File.Exists(crtPath) || !File.Exists(keyPath))
{
    using (var rsa = RSA.Create(2048))
    {
        var req = new CertificateRequest("CN=" + host, rsa, HashAlgorithmName.SHA256, RSASignaturePadding.Pkcs1);
        req.CertificateExtensions.Add(new X509BasicConstraintsExtension(false, false, 0, false));
        req.CertificateExtensions.Add(new X509KeyUsageExtension(
            X509KeyUsageFlags.DigitalSignature | X509KeyUsageFlags.KeyEncipherment, false));
        req.CertificateExtensions.Add(new X509EnhancedKeyUsageExtension(
            new OidCollection { new Oid("1.3.6.1.5.5.7.3.1") }, false)); // serverAuth

        var san = new SubjectAlternativeNameBuilder();
        san.AddDnsName(host);
        System.Net.IPAddress ip;
        if (System.Net.IPAddress.TryParse(host, out ip)) { san.AddIpAddress(ip); }
        req.CertificateExtensions.Add(san.Build());

        using (var cert = req.CreateSelfSigned(
            DateTimeOffset.UtcNow.AddDays(-1), DateTimeOffset.UtcNow.AddYears(10)))
        {
            File.WriteAllText(crtPath, toPem("CERTIFICATE", cert.Export(X509ContentType.Cert)));
            File.WriteAllText(keyPath, toPem("PRIVATE KEY", rsa.ExportPkcs8PrivateKey()));
        }
    }
    if (!System.OperatingSystem.IsWindows())
    {
        try { File.SetUnixFileMode(keyPath, UnixFileMode.UserRead | UnixFileMode.UserWrite); } catch { }
    }
}

// Enable mod_ssl + mod_socache_shmcb by dropping their load files into
// /etc/apache2/mods-enabled (Debian loads mods-enabled/*.load before sites).
var sslLoadPath = Path.Combine(tlsDir, "ssl.load");
var socacheLoadPath = Path.Combine(tlsDir, "socache_shmcb.load");
var sslConfPath = Path.Combine(tlsDir, "ssl.conf");
var vhostPath = Path.Combine(tlsDir, "default-ssl.conf");

File.WriteAllText(sslLoadPath, "LoadModule ssl_module /usr/lib/apache2/modules/mod_ssl.so\n");
File.WriteAllText(socacheLoadPath, "LoadModule socache_shmcb_module /usr/lib/apache2/modules/mod_socache_shmcb.so\n");

File.WriteAllText(sslConfPath,
    "SSLRandomSeed startup builtin\n" +
    "SSLRandomSeed startup file:/dev/urandom 512\n" +
    "SSLRandomSeed connect builtin\n" +
    "SSLRandomSeed connect file:/dev/urandom 512\n" +
    "AddType application/x-x509-ca-cert .crt\n" +
    "AddType application/x-pkcs7-crl .crl\n" +
    "SSLPassPhraseDialog builtin\n" +
    "SSLSessionCache shmcb:/var/run/apache2/ssl_scache(512000)\n" +
    "SSLSessionCacheTimeout 300\n" +
    "SSLProtocol all -SSLv3 -TLSv1 -TLSv1.1\n" +
    "SSLCipherSuite HIGH:!aNULL:!MD5\n" +
    "SSLHonorCipherOrder on\n");

// NOTE: no "Listen 443" here. The base image already listens on 443 once
// mod_ssl is loaded (its ports.conf has `<IfModule ssl_module> Listen 443`),
// so adding our own would trip apache's "Cannot define multiple Listeners on
// the same IP:port". We only need to declare the vhost.
File.WriteAllText(vhostPath,
    "<VirtualHost *:443>\n" +
    "    DocumentRoot /var/www/html\n" +
    "    SSLEngine on\n" +
    "    SSLCertificateFile    /etc/ssl/phpmyadmin/server.crt\n" +
    "    SSLCertificateKeyFile /etc/ssl/phpmyadmin/server.key\n" +
    "    <Directory /var/www/html>\n" +
    "        Options -Indexes +FollowSymLinks\n" +
    "        AllowOverride None\n" +
    "        Require all granted\n" +
    "    </Directory>\n" +
    "</VirtualHost>\n");

startParams.HostConfig.Mounts ??= new List<Mount>();
startParams.HostConfig.Mounts.Add(new Mount { Type = "bind", Source = crtPath, Target = "/etc/ssl/phpmyadmin/server.crt", ReadOnly = true });
startParams.HostConfig.Mounts.Add(new Mount { Type = "bind", Source = keyPath, Target = "/etc/ssl/phpmyadmin/server.key", ReadOnly = true });
startParams.HostConfig.Mounts.Add(new Mount { Type = "bind", Source = sslLoadPath, Target = "/etc/apache2/mods-enabled/ssl.load", ReadOnly = true });
startParams.HostConfig.Mounts.Add(new Mount { Type = "bind", Source = socacheLoadPath, Target = "/etc/apache2/mods-enabled/socache_shmcb.load", ReadOnly = true });
startParams.HostConfig.Mounts.Add(new Mount { Type = "bind", Source = sslConfPath, Target = "/etc/apache2/mods-enabled/ssl.conf", ReadOnly = true });
startParams.HostConfig.Mounts.Add(new Mount { Type = "bind", Source = vhostPath, Target = "/etc/apache2/sites-enabled/default-ssl.conf", ReadOnly = true });
